  console.log("Bot has connected to Discord! ");
});

client.on("messageCreate", (message) => {
  if (message.content.includes("ban")) {
    const args = message.content.substring(6).split(" ");

    const reason = args.slice(1).join(" ") || "No reason given.";

    const member = message.guild.members.cache.get(args[0]);

    if (!member) {
      return message.reply("Member not found. ");
    }

    if (member.permissions.has("BAN_MEMBERS")) {
      return message.reply("I can't ban myself or a member with the Ban Members permission. ");
    }

    member.ban({
      reason: reason,
    });

    message.reply(`Successfully banned member ${message.mentions.users.first().username} for ${reason}.`);
  }
});

client.login("YOUR_BOT_TOKEN");
```

