        cout << "Error: unable to open text file." << endl;
        return 1;
    }

    // Get the specific word to count occurrences of from the user
    string search_word;
    cout << "Enter the word to count occurrences of: ";
    cin >> search_word;

    // Count the number of occurrences of the search word in the lines from the text file
    int count = 0;
    for (size_t i = 0; i < lines.size(); i++) {
        size_t pos = lines[i].find(search_word);
        while (pos != string::npos) {
            count++;
            pos = lines[i].find(search_word, pos + 1));
        }
    }

    // Print the number of occurrences of the search word
    cout << "The word \"" << search_word << "\" appears " << count << " time(s) in the text file." << endl;

    return 0;
}
